import React, { useState } from "react";
import { api } from "../../api";
import "../RegisterPage/RegisterPage.css"; // Используем те же стили

export default function LoginPage({ onNavigate, onSuccess }) {
    const LoginPage = ({ onNavigate, onSuccess }) => {
        const [email, setEmail] = useState("");
        const [password, setPassword] = useState("");

        const handleSubmit = async (e) => {
            e.preventDefault();
            try {
                const data = await api.login({ email, password });
                if (data.accessToken) {
                    onSuccess(data.accessToken, data.user); 
                }
            } catch (err) {
                alert("Ошибка входа: " + err.response?.data?.error);
            }
        };
    }

    return (
    <div className="login-container">
      <form onSubmit={handleSubmit}>
        <h2>Вход в магазин</h2>
        
        <input
          type="email"
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
        />

        <input
          type="password"
          placeholder="Пароль"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
        />

        <button type="submit">Войти</button>
      </form>

      <p>
        Нет аккаунта?{" "}
        <span style={{color: 'blue', cursor: 'pointer'}} onClick={onNavigate}>
          Зарегистрироваться
        </span>
      </p>
    </div>
  );
}
